532: 	if err != nil {
533: 		return nil, err
534: 	}
535: 	node := []*framework.NodeInfo{nodeInfo}
536: 	feasibleNodes, err := sched.findNodesThatPassFilters(ctx, fwk, state, pod, &diagnosis, node)
537: 	if err != nil {
538: 		return nil, err
539: 	}
540: 
541: 	feasibleNodes, err = findNodesThatPassExtenders(ctx, sched.Extenders, pod, feasibleNodes, diagnosis.NodeToStatusMap)
542: 	if err != nil {
