549: // hasScoring checks if scoring nodes is configured.
550: func (sched *Scheduler) hasScoring(fwk framework.Framework) bool {
551: 	if fwk.HasScorePlugins() {
552: 		return true
553: 	}
554: 	for _, extender := range sched.Extenders {
555: 		if extender.IsPrioritizer() {
556: 			return true
557: 		}
558: 	}
559: 	return false
560: }
