572: // findNodesThatPassFilters finds the nodes that fit the filter plugins.
573: func (sched *Scheduler) findNodesThatPassFilters(
574: 	ctx context.Context,
575: 	fwk framework.Framework,
576: 	state *framework.CycleState,
577: 	pod *v1.Pod,
578: 	diagnosis *framework.Diagnosis,
579: 	nodes []*framework.NodeInfo) ([]*framework.NodeInfo, error) {
580: 	numAllNodes := len(nodes)
581: 	numNodesToFind := sched.numFeasibleNodesToFind(fwk.PercentageOfNodesToScore(), int32(numAllNodes))
582: 	if !sched.hasExtenderFilters() && !sched.hasScoring(fwk) {
583: 		numNodesToFind = 1
584: 	}
585: 
586: 	// Create feasible list with enough space to avoid growing it
587: 	// and allow assigning.
588: 	feasibleNodes := make([]*framework.NodeInfo, numNodesToFind)
589: 
590: 	if !fwk.HasFilterPlugins() {
591: 		for i := range feasibleNodes {
592: 			feasibleNodes[i] = nodes[(sched.nextStartNodeIndex+i)%numAllNodes]
593: 		}
594: 		return feasibleNodes, nil
595: 	}
596: 
597: 	errCh := parallelize.NewErrorChannel()
598: 	var feasibleNodesLen int32
599: 	ctx, cancel := context.WithCancel(ctx)
600: 	defer cancel()
601: 
602: 	type nodeStatus struct {
603: 		node   string
604: 		status *framework.Status
605: 	}
606: 	result := make([]*nodeStatus, numAllNodes)
607: 	checkNode := func(i int) {
608: 		// We check the nodes starting from where we left off in the previous scheduling cycle,
609: 		// this is to make sure all nodes have the same chance of being examined across pods.
610: 		nodeInfo := nodes[(sched.nextStartNodeIndex+i)%numAllNodes]
611: 		status := fwk.RunFilterPluginsWithNominatedPods(ctx, state, pod, nodeInfo)
612: 		if status.Code() == framework.Error {
613: 			errCh.SendErrorWithCancel(status.AsError(), cancel)
614: 			return
615: 		}
616: 		if status.IsSuccess() {
617: 			length := atomic.AddInt32(&feasibleNodesLen, 1)
618: 			if length > numNodesToFind {
619: 				cancel()
620: 				atomic.AddInt32(&feasibleNodesLen, -1)
621: 			} else {
622: 				feasibleNodes[length-1] = nodeInfo
623: 			}
624: 		} else {
625: 			result[i] = &nodeStatus{node: nodeInfo.Node().Name, status: status}
626: 		}
627: 	}
628: 
629: 	beginCheckNode := time.Now()
630: 	statusCode := framework.Success
631: 	defer func() {
632: 		// We record Filter extension point latency here instead of in framework.go because framework.RunFilterPlugins
633: 		// function is called for each node, whereas we want to have an overall latency for all nodes per scheduling cycle.
634: 		// Note that this latency also includes latency for `addNominatedPods`, which calls framework.RunPreFilterAddPod.
635: 		metrics.FrameworkExtensionPointDuration.WithLabelValues(metrics.Filter, statusCode.String(), fwk.ProfileName()).Observe(metrics.SinceInSeconds(beginCheckNode))
636: 	}()
637: 
638: 	// Stops searching for more nodes once the configured number of feasible nodes
639: 	// are found.
640: 	fwk.Parallelizer().Until(ctx, numAllNodes, checkNode, metrics.Filter)
641: 	feasibleNodes = feasibleNodes[:feasibleNodesLen]
642: 	for _, item := range result {
643: 		if item == nil {
644: 			continue
645: 		}
646: 		diagnosis.NodeToStatusMap[item.node] = item.status
647: 		diagnosis.AddPluginStatus(item.status)
648: 	}
649: 	if err := errCh.ReceiveError(); err != nil {
650: 		statusCode = framework.Error
651: 		return feasibleNodes, err
652: 	}
653: 	return feasibleNodes, nil
654: }
