656: // numFeasibleNodesToFind returns the number of feasible nodes that once found, the scheduler stops
657: // its search for more feasible nodes.
658: func (sched *Scheduler) numFeasibleNodesToFind(percentageOfNodesToScore *int32, numAllNodes int32) (numNodes int32) {
659: 	if numAllNodes < minFeasibleNodesToFind {
660: 		return numAllNodes
661: 	}
662: 
663: 	// Use profile percentageOfNodesToScore if it's set. Otherwise, use global percentageOfNodesToScore.
664: 	var percentage int32
665: 	if percentageOfNodesToScore != nil {
666: 		percentage = *percentageOfNodesToScore
667: 	} else {
668: 		percentage = sched.percentageOfNodesToScore
669: 	}
670: 
671: 	if percentage == 0 {
672: 		percentage = int32(50) - numAllNodes/125
673: 		if percentage < minFeasibleNodesPercentageToFind {
674: 			percentage = minFeasibleNodesPercentageToFind
675: 		}
676: 	}
677: 
678: 	numNodes = numAllNodes * percentage / 100
679: 	if numNodes < minFeasibleNodesToFind {
680: 		return minFeasibleNodesToFind
681: 	}
682: 
683: 	return numNodes
684: }
